fn e2e_layered_gradient_ui() {
    // Create renderer
    let mut renderer = Renderer::new(80, 24)?;

    // Layer 0: Background gradient
    renderer.render_to_layer(0, |buf| {
        buf.fill_gradient_vertical(
            Rect::new(0, 0, 80, 24),
            Rgba::from_hex("#1a1a2e"),
            Rgba::from_hex("#16213e")
        );
    });

    // Layer 1: Content panel
