        buf.fill_rect(10, 5, 60, 14, Rgba::with_alpha(0.9));
        buf.draw_box(10, 5, 60, 14, BoxStyle::Double);
    });

    // Merge and present
    renderer.merge_layers();
    renderer.present()?;

    // Verify hit testing
    assert!(renderer.hit_test(5, 5).unwrap() == 0);  // Background layer
    assert!(renderer.hit_test(20, 10).unwrap() == 1); // Content layer
}
```

